return items.map(item => {
  // Get the URL and clean it (remove extra spaces around colon)
  const rawUrl = item.json.url?.trim();

  // Clean the URL: fix spaces around colon in bot token
  const cleanedUrl = rawUrl ? rawUrl.replace(/\s+:/g, ':').replace(/:\s+/g, ':') : null;

  return {
    json: {
      type: "image_url",
      image_url: {
        url: cleanedUrl
      }
    },
    pairedItem: item.pairedItem,
  };
});// Loop over input items and add a new field

